async (params, browser) => {
  // Open Coinbase search
  await browser.open(`https://www.coinbase.com/explore?query=${params.query}`)

  // Wait for results
  await browser.waitForSelector('table, a[href*=\'/price/\']', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('table tbody tr, a[href*="/price/"]').forEach((el, i) => { if (i >= 20) return; const link = el.querySelector('a[href*="/price/"]') || (el.matches?.('a[href*="/price/"]') ? el : null); const name = el.querySelector('td:first-child, h2, p')?.textContent?.trim() || el.textContent?.trim() || ''; const price = el.querySelector('td:nth-child(2), [class*="Price"]')?.textContent?.trim() || ''; const change = el.querySelector('td:nth-child(3), [class*="Change"]')?.textContent?.trim() || ''; const href = link?.getAttribute?.('href') || ''; const url = href.startsWith('/') ? 'https://www.coinbase.com' + href : href; if (name && name.length < 100) results.push({ name, url, price, change }); }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
